@add_start_docstrings(
    "The bare Qwen3 Model outputting raw hidden-states without any specific head on top.",
    QWEN3_START_DOCSTRING,
)
class Qwen3Model(Qwen3PreTrainedModel):
    """
    Transformer decoder consisting of *config.num_hidden_layers* layers. Each layer is a [`Qwen3DecoderLayer`]

    Args:
        config: Qwen3Config
    """

    def __init__(self, config: Qwen3Config):
        super().__init__(config)
        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size

        self.embed_tokens = nn.Embedding(config.vocab_size, config.hidden_size, self.padding_idx)
        self.layers = nn.ModuleList(
            [Qwen3DecoderLayer(config, layer_idx) for layer_idx in range(config.num_hidden_layers)]
        )
        self.norm = Qwen3RMSNorm(config.hidden_size, eps=config.rms_norm_eps)
        self.rotary_emb = Qwen3RotaryEmbedding(config=config)
        self.gradient_checkpointing = False

        self.audio_model = AudioEncoder(config)
        self.audio_projection = ResamplerProjector(
            512, config.hidden_size,
            getattr(config, 'audio_projection_norm_type', 'layer_norm')
        )

        if config.use_speaker_embedding:
            self.speaker_projection = SpeakerProjector(
                config.speaker_embedding_size,
                config.hidden_size,
                getattr(config, 'audio_projection_norm_type', 'layer_norm')
            )


        # Initialize weights and apply final processing
        self.post_init()


    def get_input_embeddings(self):
        return self.embed_tokens

    def set_input_embeddings(self, value):
        self.embed_tokens = value

    @can_return_tuple
    @add_start_docstrings_to_model_forward(QWEN3_INPUTS_DOCSTRING)
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        attention_mask: Optional[torch.Tensor] = None,
        audios: Optional[torch.FloatTensor] = None,
        audio_indices: Optional[torch.LongTensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        use_cache: Optional[bool] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        cache_position: Optional[torch.LongTensor] = None,
        layer_idxs = None,
        audio_tokens : Optional[torch.LongTensor] = None,
        audio_token_starts : Optional[torch.LongTensor] = None,
        audio_token_ends : Optional[torch.LongTensor] = None,
        speaker_embeddings : Optional[torch.FloatTensor] = None,
        speaker_mask : Optional[torch.Tensor] = None,
        **flash_attn_kwargs: Unpack[FlashAttentionKwargs],
    ) -> BaseModelOutputWithPast:
        if (past_key_values is None or len(past_key_values) == 0) and audios is not None:
            audio_embeds, audio_lengths = self.audio_model(audios)
            # if torch.distributed.get_rank() == 0:
            #     print(f"audio_embeds {audio_embeds.size()}")
            assert audio_embeds.shape[0] == len(audios)
            fake_audios = None
            audio_embeds = self.audio_projection(audio_embeds)
        elif self.training:
            device = self.get_input_embeddings().weight.data.device
            dtype = self.get_input_embeddings().weight.data.dtype
            fake_audios = torch.ones((1, 1, 560), dtype=dtype, device=device)
            audio_embeds, audio_lengths = self.audio_model(fake_audios)
            audio_embeds = self.audio_projection(audio_embeds)

        else:
            fake_audios = None
            audio_embeds = None

        if (past_key_values is None or len(past_key_values) == 0) and speaker_embeddings is not None:
            # import pdb; pdb.set_trace()
            # if torch.distributed.get_rank() == 0:
            #     print(f"audio_embeds {audio_embeds.size()}")
            fake_speakers = None
            speaker_embeds = self.speaker_projection(speaker_embeddings)
            assert speaker_embeds.shape[0] == len(speaker_embeddings)
        elif self.training:
            device = self.get_input_embeddings().weight.data.device
            dtype = self.get_input_embeddings().weight.data.dtype
            fake_speakers = torch.ones((1, 1, 192), dtype=dtype, device=device)
            speaker_embeds = self.speaker_projection(fake_speakers)
        else:
            fake_speakers = None
            speaker_embeds = None



        output_attentions = output_attentions if output_attentions is not None else self.config.output_attentions
        output_hidden_states = (
            output_hidden_states if output_hidden_states is not None else self.config.output_hidden_states
        )
        use_cache = use_cache if use_cache is not None else self.config.use_cache

        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError("You must specify exactly one of input_ids or inputs_embeds")

        if self.gradient_checkpointing and self.training and use_cache:
            logger.warning_once(
                "`use_cache=True` is incompatible with gradient checkpointing. Setting `use_cache=False`."
            )
            use_cache = False

        # TODO (joao): remove this exception in v4.56 -- it exists for users that try to pass a legacy cache
        if not isinstance(past_key_values, (type(None), Cache)):
            raise ValueError("The `past_key_values` should be either a `Cache` object or `None`.")

        if inputs_embeds is None:
            inputs_embeds = self.embed_tokens(input_ids)

        if audio_tokens is not None and audio_tokens.numel() > 0:
            audio_tokens_embeds = self.embed_tokens(audio_tokens) # 8 x T => 8 x T x H
            audio_start_positions, audio_end_positions = [], []
            audio_token_mask = torch.zeros(inputs_embeds.shape[:-1]).bool() # B x T
            if len(audio_token_starts) == 1:
                for _audio_start, _audio_end in zip(audio_token_starts[0], audio_token_ends[0]):
                    audio_token_mask[:, _audio_start: _audio_end] = True
            else:
                # audio_token_starts B x T, audio_token_ends B x T
                for i, (_audio_token_starts, _audio_token_ends) in enumerate(zip(audio_token_starts, audio_token_ends)):
                    for _audio_start, _audio_end in zip(_audio_token_starts, _audio_token_ends):
                        audio_token_mask[i, _audio_start: _audio_end] = True
                        import pdb; pdb.set_trace()
            inputs_embeds[audio_token_mask] = audio_tokens_embeds.squeeze(0).mean(0) # 8 x T x H => T x H
            assert not torch.isnan(inputs_embeds).any(), f"{inputs_embeds=} {inputs_embeds.size()=}"
        assert not torch.isnan(self.embed_tokens.weight).any(), f"{self.embed_tokens.weight=} {self.embed_tokens.weight.size()=}"

        if fake_audios is not None:
            inputs_embeds = inputs_embeds + audio_embeds.mean() * 0.0
        elif audio_embeds is not None:
            inputs_embeds = inputs_embeds.clone()
            for audio_embeds_, audio_lengths_, audio_indices_ in zip(audio_embeds, audio_lengths, audio_indices,):
                # print(f"{audio_embeds_.size()=} {audio_lengths_=} {audio_indices_.size()=}")
                audio_embeds_ = audio_embeds_[:audio_lengths_, ...]
                audio_embeds_ = audio_embeds_.to(inputs_embeds.device)
                indices_b, indices_s = audio_indices_.to(inputs_embeds.device).unbind(dim=0)
                inputs_embeds[indices_b.view(-1), indices_s.view(-1)] = audio_embeds_.view(-1, audio_embeds_.shape[-1])
                assert not torch.isnan(inputs_embeds).any(), f"audio embeds {inputs_embeds=} {inputs_embeds.size()=}"
        if fake_speakers is not None:
            inputs_embeds = inputs_embeds + speaker_embeds.mean() * 0.0
        elif speaker_embeds is not None:
            inputs_embeds = inputs_embeds.clone()
            inputs_embeds[speaker_mask.bool()] = speaker_embeds
            assert not torch.isnan(inputs_embeds).any(), f"audio embeds {inputs_embeds=} {inputs_embeds.size()=}"
            # for audio_embeds_, audio_lengths_, audio_indices_ in zip(audio_embeds, audio_lengths, audio_indices,):
            #     # print(f"{audio_embeds_.size()=} {audio_lengths_=} {audio_indices_.size()=}")
            #     audio_embeds_ = audio_embeds_[:audio_lengths_, ...]
            #     audio_embeds_ = audio_embeds_.to(inputs_embeds.device)
            #     indices_b, indices_s = audio_indices_.to(inputs_embeds.device).unbind(dim=0)
            #     inputs_embeds[indices_b.view(-1), indices_s.view(-1)] = audio_embeds_.view(-1, audio_embeds_.shape[-1])
            #     assert not torch.isnan(inputs_embeds).any(), f"audio embeds {inputs_embeds=} {inputs_embeds.size()=}"
        # import pdb; pdb.set_trace()

        if use_cache and past_key_values is None:
            past_key_values = DynamicCache()

        if cache_position is None:
            past_seen_tokens = past_key_values.get_seq_length() if past_key_values is not None else 0
            cache_position = torch.arange(
                past_seen_tokens, past_seen_tokens + inputs_embeds.shape[1], device=inputs_embeds.device
            )

        if position_ids is None:
            position_ids = cache_position.unsqueeze(0)

        causal_mask = self._update_causal_mask(
            attention_mask, inputs_embeds, cache_position, past_key_values, output_attentions
        )

        hidden_states = inputs_embeds

        # create position embeddings to be shared across the decoder layers
        position_embeddings = self.rotary_emb(hidden_states, position_ids)

        # decoder layers
        all_hidden_states = () if output_hidden_states else None
        all_self_attns = () if output_attentions else None

        if layer_idxs is None:
            layer_idxs = list(range(self.config.num_hidden_layers))
        layers = [self.layers[layer_idx] for layer_idx in layer_idxs]

        for decoder_layer in layers:
            if output_hidden_states:
                all_hidden_states += (hidden_states,)

            if self.gradient_checkpointing and self.training:
                layer_outputs = self._gradient_checkpointing_func(
                    partial(decoder_layer.__call__, **flash_attn_kwargs),
                    hidden_states,
                    causal_mask,
                    position_ids,
                    past_key_values,
                    output_attentions,
                    use_cache,
                    cache_position,
                    position_embeddings,
                )
            else:
                layer_outputs = decoder_layer(
                    hidden_states,
                    attention_mask=causal_mask,
                    position_ids=position_ids,
                    past_key_value=past_key_values,
                    output_attentions=output_attentions,
                    use_cache=use_cache,
                    cache_position=cache_position,
                    position_embeddings=position_embeddings,
                    **flash_attn_kwargs,
                )

            hidden_states = layer_outputs[0]

            if output_attentions:
                all_self_attns += (layer_outputs[1],)

        hidden_states = self.norm(hidden_states)

        # add hidden states from the last decoder layer
        if output_hidden_states:
            all_hidden_states += (hidden_states,)

        return Qwen3ModelOutput(
            last_hidden_state=hidden_states,
            past_key_values=past_key_values if use_cache else None,
            hidden_states=all_hidden_states,
            attentions=all_self_attns,
            inputs_embeds=inputs_embeds,
        )

    def _update_causal_mask(
        self,
        attention_mask: torch.Tensor,
        input_tensor: torch.Tensor,
        cache_position: torch.Tensor,
        past_key_values: Cache,
        output_attentions: bool = False,
    ):
        if self.config._attn_implementation == "flash_attention_2":
            if attention_mask is not None and past_key_values is not None:
                is_padding_right = attention_mask[:, -1].sum().item() != input_tensor.size()[0]
                if is_padding_right:
                    raise ValueError(
                        "You are attempting to perform batched generation with padding_side='right'"
                        " this may lead to unexpected behaviour for Flash Attention version of Qwen3. Make sure to "
                        " call `tokenizer.padding_side  = 'left'` before tokenizing the input. "
                    )
            if attention_mask is not None and 0.0 in attention_mask:
                return attention_mask
            return None

        # For SDPA, when possible, we will rely on its `is_causal` argument instead of its `attn_mask` argument, in
        # order to dispatch on Flash Attention 2. This feature is not compatible with static cache, as SDPA will fail
        # to infer the attention mask.
        past_seen_tokens = past_key_values.get_seq_length() if past_key_values is not None else 0
        using_static_cache = isinstance(past_key_values, StaticCache)
        using_sliding_window_cache = isinstance(past_key_values, SlidingWindowCache)

        # When output attentions is True, sdpa implementation's forward method calls the eager implementation's forward
        if (
            self.config._attn_implementation == "sdpa"
            and not (using_static_cache or using_sliding_window_cache)
            and not output_attentions
        ):
            if AttentionMaskConverter._ignore_causal_mask_sdpa(
                attention_mask,
                inputs_embeds=input_tensor,
                past_key_values_length=past_seen_tokens,
                sliding_window=self.config.sliding_window,
                is_training=self.training,
            ):
                return None

        dtype, device = input_tensor.dtype, input_tensor.device
        min_dtype = torch.finfo(dtype).min
        sequence_length = input_tensor.shape[1]
        # SlidingWindowCache or StaticCache
        if using_sliding_window_cache or using_static_cache:
            target_length = past_key_values.get_max_cache_shape()
        # DynamicCache or no cache
        else:
            target_length = (
                attention_mask.shape[-1]
                if isinstance(attention_mask, torch.Tensor)
                else past_seen_tokens + sequence_length + 1
            )

        # In case the provided `attention` mask is 2D, we generate a causal mask here (4D).
        causal_mask = self._prepare_4d_causal_attention_mask_with_cache_position(
            attention_mask,
            sequence_length=sequence_length,
            target_length=target_length,
            dtype=dtype,
            device=device,
            cache_position=cache_position,
            batch_size=input_tensor.shape[0],
            config=self.config,
            past_key_values=past_key_values,
        )

        if (
            self.config._attn_implementation == "sdpa"
            and attention_mask is not None
            and attention_mask.device.type in ["cuda", "xpu"]
            and not output_attentions
        ):
            # Attend to all tokens in fully masked rows in the causal_mask, for example the relevant first rows when
            # using left padding. This is required by F.scaled_dot_product_attention memory-efficient attention path.
            # Details: https://github.com/pytorch/pytorch/issues/110213
            causal_mask = AttentionMaskConverter._unmask_unattended(causal_mask, min_dtype)

        return causal_mask

    @staticmethod
    def _prepare_4d_causal_attention_mask_with_cache_position(
        attention_mask: torch.Tensor,
        sequence_length: int,
        target_length: int,
        dtype: torch.dtype,
        device: torch.device,
        cache_position: torch.Tensor,
        batch_size: int,
        config: Qwen3Config,
        past_key_values: Cache,
    ):
        """
        Creates a causal 4D mask of shape `(batch_size, 1, query_length, key_value_length)` from a 2D mask of shape
        `(batch_size, key_value_length)`, or if the input `attention_mask` is already 4D, do nothing.

        Args:
            attention_mask (`torch.Tensor`):
                A 2D attention mask of shape `(batch_size, key_value_length)` or a 4D attention mask of shape `(batch_size, 1, query_length, key_value_length)`.
            sequence_length (`int`):
                The sequence length being processed.
            target_length (`int`):
                The target length: when generating with static cache, the mask should be as long as the static cache, to account for the 0 padding, the part of the cache that is not filled yet.
            dtype (`torch.dtype`):
                The dtype to use for the 4D attention mask.
            device (`torch.device`):
                The device to place the 4D attention mask on.
            cache_position (`torch.Tensor`):
                Indices depicting the position of the input sequence tokens in the sequence.
            batch_size (`torch.Tensor`):
                Batch size.
            config (`Qwen3Config`):
                The model's configuration class
            past_key_values (`Cache`):
                The cache class that is being used currently to generate
        """
        if attention_mask is not None and attention_mask.dim() == 4:
            # In this case we assume that the mask comes already in inverted form and requires no inversion or slicing.
            causal_mask = attention_mask
        else:
            min_dtype = torch.finfo(dtype).min
            causal_mask = torch.full(
                (sequence_length, target_length), fill_value=min_dtype, dtype=dtype, device=device
            )
            diagonal_attend_mask = torch.arange(target_length, device=device) > cache_position.reshape(-1, 1)
            if config.sliding_window is not None:
                # if we have sliding window, we should not attend to tokens beyond sliding window length, so we mask them out also
                # the check is needed to verify is current checkpoint was trained with sliding window or not
                if not isinstance(past_key_values, SlidingWindowCache) or sequence_length > target_length:
                    sliding_attend_mask = torch.arange(target_length, device=device) <= (
                        cache_position.reshape(-1, 1) - config.sliding_window
                    )
                    diagonal_attend_mask.bitwise_or_(sliding_attend_mask)
            causal_mask *= diagonal_attend_mask
            causal_mask = causal_mask[None, None, :, :].expand(batch_size, 1, -1, -1)
            if attention_mask is not None:
                causal_mask = causal_mask.clone()  # copy to contiguous memory for in-place edit
                if attention_mask.shape[-1] > target_length:
                    attention_mask = attention_mask[:, :target_length]
                mask_length = attention_mask.shape[-1]
                padding_mask = causal_mask[:, :, :, :mask_length] + attention_mask[:, None, None, :].to(
                    causal_mask.device
                )
                padding_mask = padding_mask == 0
                causal_mask[:, :, :, :mask_length] = causal_mask[:, :, :, :mask_length].masked_fill(
                    padding_mask, min_dtype
                )
        return causal_mask


class KwargsForCausalLM(FlashAttentionKwargs, LossKwargs): ...


class Qwen3MTPSenseVoiceForCausalLM(Qwen3PreTrainedModel, GenerationMixin):
    _tied_weights_keys = ["lm_head.weight"]
    _tp_plan = {"lm_head": "colwise_rep"}
    _pp_plan = {"lm_head": (["hidden_states"], ["logits"])}

    def __init__(self, config):
        super().__init__(config)
        self.model = Qwen3Model(config)
        self.vocab_size = config.vocab_size
        self.lm_head = nn.Linear(config.hidden_size, config.vocab_size, bias=False)

        self.mtp_projs = nn.ModuleList(
            [nn.Linear(2 * config.hidden_size, config.hidden_size, bias=False) for _ in range(self.config.num_nextn_predict_layers)]
        )

        self.mtp_embed_norms = nn.ModuleList([Qwen3RMSNorm(config.hidden_size, eps=config.rms_norm_eps) for _ in range(self.config.num_nextn_predict_layers)])
        self.mtp_hidden_norms = nn.ModuleList([Qwen3RMSNorm(config.hidden_size, eps=config.rms_norm_eps) for _ in range(self.config.num_nextn_predict_layers)])
        # Initialize weights and apply final processing
        if config.use_audio_heads:
            self.audio_heads = nn.ModuleList([
                nn.Linear(config.hidden_size, config.codebook_size, bias=False)
                for _ in range(config.num_codebook-1)
            ])

        self.post_init()

        # self.mtp_embed_norms[0].weight.data = 1.
        # self.mtp_hidden_norms[0].weight.data = 1.



    def get_input_embeddings(self):
        return self.model.embed_tokens

    def set_input_embeddings(self, value):
        self.model.embed_tokens = value

    def get_output_embeddings(self):
        return self.lm_head

    def set_output_embeddings(self, new_embeddings):
        self.lm_head = new_embeddings

    def set_decoder(self, decoder):
        self.model = decoder

    def get_decoder(self):
        return self.model

    def mtp_forward(
        self,
        mtp_idx,
        input_ids: torch.LongTensor = None,
        hidden_states: torch.Tensor = None,
        attention_mask: Optional[torch.Tensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        labels: Optional[torch.LongTensor] = None,
        kl_labels: Optional[torch.Tensor] = None,
        use_cache: Optional[bool] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        return_dict: Optional[bool] = None,
        cache_position: Optional[torch.LongTensor] = None,
        num_logits_to_keep: int = 0,
        audio_labels : Optional[torch.LongTensor] = None,
        audio_token_starts : Optional[torch.LongTensor] = None,
        audio_token_ends : Optional[torch.LongTensor] = None,
        **kwargs: Unpack[KwargsForCausalLM],
    ) -> Union[Tuple, BaseModelOutputWithPast]:
        global text_vocab_size
        if (input_ids is None) ^ (inputs_embeds is not None):
            raise ValueError("You must specify exactly one of input_ids or inputs_embeds")

        if inputs_embeds is None:
            inputs_embeds = self.model.embed_tokens(input_ids)
            # inputs_embeds = inputs_embeds.to(hidden_states.device)

        inputs_embeds = torch.cat(
            (
                self.mtp_embed_norms[mtp_idx](inputs_embeds),
                self.mtp_hidden_norms[mtp_idx](hidden_states),
            ),
            dim=-1,
        )

        inputs_embeds = self.mtp_projs[mtp_idx](inputs_embeds)

        outputs = self.model(
            input_ids=None,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
            return_dict=return_dict,
            cache_position=cache_position,
            layer_idxs=[self.config.num_hidden_layers - self.config.num_nextn_predict_layers + mtp_idx],
            **kwargs,
        )

        hidden_states = outputs[0]
        logits = self.lm_head(hidden_states[:, -num_logits_to_keep:, :])
        codebook_size = self.config.codebook_size
        if text_vocab_size is not None and hasattr(self, 'audio_heads'):
            for i, audio_head in enumerate(self.audio_heads):
                audio_logits = audio_head(hidden_states[:, slice_indices, :])
                audio_logits_s = text_vocab_size + i * codebook_size
                audio_logits_e = text_vocab_size + (i+1) * codebook_size
                logits[:,:,audio_logits_s:audio_logits_e] = audio_logits

        if labels is not None:
            loss = []
            ce_loss_text, ce_loss_audio, _loss = self.compute_xy_loss(
                logits,
                labels,
                audio_labels,
                audio_token_starts,
                audio_token_ends,
                mtp_idx=mtp_idx,
                audio_logits=audio_logits,
                **kwargs
            )
            # ce_loss_text, ce_loss_audio, _loss = self.compute_xy_loss(logits, labels, audio_labels, audio_token_starts, audio_token_ends, mtp=True, **kwargs)
            loss += [_loss]
            # ce_loss = self.loss_function(logits=logits, labels=labels, vocab_size=self.config.vocab_size, **kwargs)
            # ce_loss = ForCausalLMLoss(logits=logits, labels=labels, vocab_size=self.config.vocab_size, **kwargs)

            # loss += [ce_loss]

            # if False:
            #     kl_logits = logits.contiguous()
            #     kl_labels = kl_labels.contiguous()
            #     kl_loss = compute_kl_loss(kl_logits, kl_labels)

            #     kl_loss_weight = 1
            #     loss += [kl_loss_weight * kl_loss]

            # if self.training and torch.distributed.is_initialized() and torch.distributed.get_rank() == 0:
            #     with torch.no_grad():
            #         logger.info(f"\tMTP {mtp_idx=} {loss=}")
        else:
            loss = None

        return outputs, logits, loss

    def compute_xy_loss(
        self,
        logits,
        labels,
        audio_labels,
        audio_token_starts,
        audio_token_ends,
        mtp_idx=-1,
        **kwargs
    ):
        global text_vocab_size
        num_codebook = self.config.num_codebook
        codebook_size = self.config.codebook_size
        audio_token_mask = torch.zeros(logits.shape[:-1]).bool()
        audio_label_mask = torch.zeros(logits.shape[:-1]).bool()
        for _audio_start, _audio_end in zip(audio_token_starts[0], audio_token_ends[0]):
            audio_label_mask[:, _audio_start: _audio_end] = True
            audio_token_mask[:, _audio_start-1: _audio_end-1] = True
        text_token_mask = ~audio_token_mask
        text_label_mask = ~audio_label_mask
        # B x T x H
        audio_vocab_size = (num_codebook-1) * codebook_size
        logits_text = torch.cat([
            logits[..., :text_vocab_size].contiguous(),
            # logits.new(*logits.shape[:-1], (num_codebook-1)*codebook_size).fill_(torch.finfo(logits.dtype).min),
            logits[..., text_vocab_size+audio_vocab_size:].contiguous(),
        ], dim=-1)
        # import pdb; pdb.set_trace()

        # skip 7 codebook (7 * 1032)
        labels_text = labels.contiguous()
        labels_text[(labels_text>=0)&(labels_text>=text_vocab_size+audio_vocab_size)] -= audio_vocab_size
        ce_loss_text = ForCausalLMLoss(
            logits=logits_text,
            labels=labels_text,
            vocab_size=logits_text.shape[-1],
            shift=True, **kwargs
        )

        # import pdb; pdb.set_trace()
        num_text_labels = labels[text_label_mask].ne(-100).sum()
        num_audio_labels = audio_token_mask.sum()
        num_labels = labels.ne(-100).sum()
        # assert (labels[audio_label_mask] >= 151691).all()
        # if is_main_process():
        #     logger.info(
        #         f"{num_text_labels=} + {num_audio_labels=} == {num_labels=} {logits.shape=} {labels.shape=} {audio_label_mask.sum()=}")
        assert num_text_labels + num_audio_labels == num_labels, \
            f"{mtp_idx=} {num_text_labels=} + {num_audio_labels=} == {num_labels=}"

        ce_loss_audio, ce_loss_audios = 0, []
        if audio_label_mask.any():
            for i in range(1, num_codebook): # text_vocab_size start from <audio_1_0>
                logits_s = text_vocab_size + (i-1)*codebook_size
                logits_e = text_vocab_size + i*codebook_size
                logits_audio_i = logits[audio_token_mask][..., logits_s:logits_e].contiguous()
                labels_audio_i = audio_labels.squeeze(0)[i].contiguous()
                ce_loss_audio_i = ForCausalLMLoss(
                    logits=logits_audio_i, labels=labels_audio_i, vocab_size=codebook_size, shift=False, **kwargs)
                ce_loss_audios.append(ce_loss_audio_i)
            ce_loss_audio = torch.stack(ce_loss_audios).mean()
            assert not torch.isnan(ce_loss_audio).any(), f"{ce_loss_audio=} {ce_loss_audio.size()=}"
        losses = [ce_loss_text] + ce_loss_audios
        _losses = torch.stack(losses).tolist()

        loss = ce_loss_text + ce_loss_audio
        if is_main_process():
            logger.info(f"mtp_idx {mtp_idx}\tavg: {loss} | text: {ce_loss_text} | audio: {ce_loss_audio} | all losses: {_losses}")
        assert not torch.isnan(loss).any(), f"{loss=} {loss.size()=}"
        return ce_loss_text, ce_loss_audio, loss

    def process_inputs(
        self, inputs_embeds,
        audio_tokens, audio_token_starts, audio_token_ends,
    ):
        if audio_tokens is not None and audio_tokens.numel() > 0:
            audio_tokens_embeds = self.model.embed_tokens(audio_tokens) # 8 x T => 8 x T x H
            audio_start_positions, audio_end_positions = [], []
            audio_token_mask = torch.zeros(inputs_embeds.shape[:-1]).bool()
            for _audio_start, _audio_end in zip(audio_token_starts[0], audio_token_ends[0]):
                audio_token_mask[:, _audio_start: _audio_end] = True
            inputs_embeds[audio_token_mask] = audio_tokens_embeds.squeeze(0).mean(0) # 8 x T x H => T x H
            assert not torch.isnan(inputs_embeds).any(), f"{inputs_embeds=} {inputs_embeds.size()=}"

        return inputs_embeds

    def get_input_size(self, dim=1):
        if self.input_ids is not None:
            return self.input_ids.size(dim)
        if self.inputs_embeds is not None:
            return self.inputs_embeds.size(dim)
        raise ValueError(f'both self.input_ids and self.inputs_embeds are None')


    @can_return_tuple
    @deprecate_kwarg("num_logits_to_keep", version="4.50", new_name="logits_to_keep")
    @add_start_docstrings_to_model_forward(QWEN3_INPUTS_DOCSTRING)
    @replace_return_docstrings(output_type=CausalLMOutputWithPast, config_class=_CONFIG_FOR_DOC)
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        attention_mask: Optional[torch.Tensor] = None,
        audios: Optional[torch.FloatTensor] = None,
        audio_indices: Optional[torch.LongTensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        labels: Optional[torch.LongTensor] = None,
        use_cache: Optional[bool] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        cache_position: Optional[torch.LongTensor] = None,
        logits_to_keep: Union[int, torch.Tensor] = 0,
        audio_tokens : Optional[torch.LongTensor] = None,
        audio_labels : Optional[torch.LongTensor] = None,
        audio_token_starts : Optional[torch.LongTensor] = None,
        audio_token_ends : Optional[torch.LongTensor] = None,
        first_audio_token_id: Optional[torch.LongTensor] = None,
        return_dict: Optional[bool] = None,
        num_logits_to_keep: int = 0,
        speaker_embeddings : Optional[torch.FloatTensor] = None,
        speaker_mask : Optional[torch.Tensor] = None,
        **kwargs: Unpack[KwargsForCausalLM],
    ) -> CausalLMOutputWithPast:
        r"""
            labels (`torch.LongTensor` of shape `(batch_size, sequence_length)`, *optional*):
                Labels for computing the masked language modeling loss. Indices should either be in `[0, ...,
                config.vocab_size]` or -100 (see `input_ids` docstring). Tokens with indices set to `-100` are ignored
                (masked), the loss is only computed for the tokens with labels in `[0, ..., config.vocab_size]`.

            logits_to_keep (`int` or `torch.Tensor`, *optional*):
                If an `int`, compute logits for the last `logits_to_keep` tokens. If `0`, calculate logits for all
                `input_ids` (special case). Only last token logits are needed for generation, and calculating them only for that
                token can save memory, which becomes pretty significant for long sequences or large vocabulary size.
                If a `torch.Tensor`, must be 1D corresponding to the indices to keep in the sequence length dimension.
                This is useful when using packed tensor format (single dimension for batch and sequence length).

        Returns:

        Example:

        ```python
        >>> from transformers import AutoTokenizer, Qwen3ForCausalLM

        >>> model = Qwen3ForCausalLM.from_pretrained("Qwen/Qwen3-8B")
        >>> tokenizer = AutoTokenizer.from_pretrained("Qwen/Qwen3-8B")

        >>> prompt = "Hey, are you conscious? Can you talk to me?"
        >>> inputs = tokenizer(prompt, return_tensors="pt")

        >>> # Generate
        >>> generate_ids = model.generate(inputs.input_ids, max_length=30)
        >>> tokenizer.batch_decode(generate_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
        "Hey, are you conscious? Can you talk to me?\nI'm not conscious, but I can talk to you."
        ```"""
        output_attentions = output_attentions if output_attentions is not None else self.config.output_attentions
        output_hidden_states = (
            output_hidden_states if output_hidden_states is not None else self.config.output_hidden_states
        )

        # ===============================================================================================
        if not self.training:
            if input_ids is not None:
                num_input_tokens = input_ids.size(1)
            if inputs_embeds is not None:
                num_input_tokens = inputs_embeds.size(1)

            if use_cache:
                if self.input_ids is None and self.inputs_embeds is None:
                    if input_ids is not None:
                        self.input_ids = input_ids
                    if inputs_embeds is not None:
                        self.inputs_embeds = inputs_embeds
                    if position_ids is not None:
                        self.position_ids = position_ids

                else:
                    if input_ids is not None:
                        self.input_ids = torch.cat([self.input_ids, input_ids], dim=1)
                    if inputs_embeds is not None:
                        self.inputs_embeds = torch.cat([self.inputs_embeds, inputs_embeds], dim=1)
                    if position_ids is not None:
                        self.position_ids = torch.cat([self.position_ids, position_ids], dim=1)

            else:
                self.input_ids = input_ids
                self.inputs_embeds = inputs_embeds
                self.position_ids = position_ids

            self.attention_mask = attention_mask

            ###
            if self.config.num_nextn_predict_layers > 0:
                if self.num_prefill_tokens < 0:
                    self.num_prefill_tokens = self.get_input_size(1)

                num_decode_tokens = self.get_input_size(1) - self.num_prefill_tokens

                if self.mtp_inference_mode[num_decode_tokens] == "M":
                    self.mtp_idx = -1
                elif self.mtp_inference_mode[num_decode_tokens] == "m":
                    if self.mtp_inference_mode[num_decode_tokens - 1] == "M":
                        self.mtp_idx = 0
                    else:
                        pass
            ####
            # if True:
            if False:
                print("=" * 100)
                print(f"{self.mtp_idx=}")
                print(f"{self.num_prefill_tokens=}")
                print(f"{num_decode_tokens=}")
                print(f"{self.mtp_inference_mode=}")
                if self.input_ids is not None:
                    print(f"{self.input_ids.size()=}")
                if self.inputs_embeds is not None:
                    print(f"{self.inputs_embeds.size()=}")
                if self.hidden_states[self.mtp_idx] is not None:
                    print(f"{self.hidden_states[self.mtp_idx].size()=}")

            # import pdb; pdb.set_trace()
            if self.mtp_idx > -1 and self.mtp_idx < self.config.num_nextn_predict_layers and num_input_tokens == 1:
                layer_idx = self.config.num_hidden_layers - self.config.num_nextn_predict_layers + self.mtp_idx

                if use_cache:
                    if len(past_key_values.key_cache) > layer_idx:
                        num_seen_tokens = past_key_values.key_cache[layer_idx].size(2)
                    else:
                        num_seen_tokens = 0
                else:
                    num_seen_tokens = 0

                hidden_states = self.hidden_states[self.mtp_idx][:, num_seen_tokens:, :]

                if self.input_ids is not None:
                    input_ids = self.input_ids[:, num_seen_tokens + self.mtp_idx +  1:]
                if self.inputs_embeds is not None:
                    inputs_embeds = self.inputs_embeds[:, num_seen_tokens + self.mtp_idx + 1:, :]
                if self.position_ids is not None:
                    position_ids = self.position_ids[:, num_seen_tokens + self.mtp_idx + 1:]
                if self.attention_mask is not None:
                    attention_mask = self.attention_mask[:, num_seen_tokens + self.mtp_idx + 1:]


                # if False:
                if True:
                    print("=" * 100)
                    print(f"{self.mtp_idx=}")
                    print(f"{layer_idx=}")
                    if input_ids is not None:
                        print(f"{input_ids.size()=} {input_ids=}")
                    if inputs_embeds is not None:
                        print(f"{inputs_embeds.size()=} {inputs_embeds=}")
                    print(f"{hidden_states.size()=} {hidden_states=}")
                    if attention_mask is not None:
                        print(f"{attention_mask.size()=} {attention_mask=}")
                    if position_ids is not None:
                        print(f"{position_ids.size()=} {position_ids=}")
                    if use_cache and len(past_key_values.key_cache) > layer_idx:
                        print(f"{past_key_values.key_cache[layer_idx].size()=}")
                    print(f"{use_cache=}")
                    print(f"{num_logits_to_keep=}")
                    print(f"{output_attentions=}")
                    print(f"{output_hidden_states=}")
                    print(f"{cache_position=}")

                mtp_outputs, logits, _ = self.mtp_forward(
                    self.mtp_idx,
                    input_ids=input_ids,
                    hidden_states=hidden_states,
                    attention_mask=attention_mask,
                    position_ids=position_ids,
                    past_key_values=past_key_values,
                    inputs_embeds=inputs_embeds,
                    labels=None,
                    kl_labels=None,
                    use_cache=use_cache,
                    output_attentions=output_attentions,
                    output_hidden_states=output_hidden_states,
                    return_dict=return_dict,
                    cache_position=cache_position,
                    num_logits_to_keep=num_logits_to_keep,
                    **kwargs,
                )
                hidden_states = mtp_outputs.last_hidden_state

                self.mtp_idx += 1
                if use_cache:
                    if self.hidden_states[self.mtp_idx] is None:
                        self.hidden_states[self.mtp_idx] = hidden_states
                    else:
                        self.hidden_states[self.mtp_idx] = torch.cat([self.hidden_states[self.mtp_idx], hidden_states], dim=1)

                else:
                    self.hidden_states[self.mtp_idx] = hidden_states

                return CausalLMOutputWithPast(
                    loss=None,
                    logits=logits,
                    past_key_values=past_key_values,
                    hidden_states=mtp_outputs.hidden_states,
                    attentions=mtp_outputs.attentions,
                )

            #if use_cache and past_key_values is not None:
            #    if len(past_key_values.key_cache) > 0:
            #        # print(f"{past_key_values.key_cache[0].size()=}")
            #        num_seen_tokens = past_key_values.key_cache[0].size(2)
            #    #
            #    #if len(past_key_values.past_key_values) > 0:
            #    #    num_seen_tokens = past_key_values.past_key_values[0].size(2)
            #    else:
            #        num_seen_tokens = 0
            #else:
            #    num_seen_tokens = 0


            if use_cache and past_key_values is not None:
                num_seen_tokens = past_key_values.get_seq_length()
            else:
                num_seen_tokens = 0


            if self.input_ids is not None:
                input_ids = self.input_ids[:, num_seen_tokens:]
            if self.inputs_embeds is not None:
                inputs_embeds = self.inputs_embeds[:, num_seen_tokens:, :]
            if self.position_ids is not None:
                position_ids = self.position_ids[:, num_seen_tokens:]
            attention_mask = attention_mask

        # ===============================================================================================
        # decoder outputs consists of (dec_features, layer_state, dec_hidden, dec_attn)
        outputs: BaseModelOutputWithPast = self.model(
            input_ids=input_ids,
            attention_mask=attention_mask,
            audios=audios,
            audio_indices=audio_indices,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
            cache_position=cache_position,
            layer_idxs=list(range(self.config.num_hidden_layers - self.config.num_nextn_predict_layers)),
            audio_tokens=audio_tokens,
            audio_token_starts=audio_token_starts,
            audio_token_ends=audio_token_ends,
            speaker_embeddings=speaker_embeddings,
            speaker_mask=speaker_mask,
            **kwargs,
        )

        hidden_states = outputs.last_hidden_state
        # Only compute necessary logits, and do not upcast them to float if we are not computing the loss
        slice_indices = slice(-logits_to_keep, None) if isinstance(logits_to_keep, int) else logits_to_keep
        logits = self.lm_head(hidden_states[:, slice_indices, :]) # B x T x H
        global text_vocab_size
        text_vocab_size = first_audio_token_id
        codebook_size = self.config.codebook_size
        if text_vocab_size is not None and hasattr(self, 'audio_heads'):
            for i, audio_head in enumerate(self.audio_heads):
                audio_logits = audio_head(hidden_states[:, slice_indices, :])
                audio_logits_s = text_vocab_size + i * codebook_size
                audio_logits_e = text_vocab_size + (i+1) * codebook_size
                logits[:,:,audio_logits_s:audio_logits_e] = audio_logits

        # |   T label   | A label   |  T label    | A label   | T label |
        # |t1||t2|t3|BOA|a1|a2|a3|a5|EOA|t5|t6|BOA|a6|a7|a8|a9|EOA|t7|t8|
        # | T token |  A token   |  T token   |  A token   |  T token   |
        # Therefore shift Text logits & labels in ForCausalLMLoss
        # do not shift Audio logits & labels in ForCausalLMLoss
        # import pdb; pdb.set_trace()
        assert not torch.isnan(logits).any(), f"{logits=} {logits.size()=}"

        loss = None

        if labels is not None:
            # audio_token_mask = torch.zeros(input_ids.shape).bool()
            # audio_label_mask = torch.zeros(input_ids.shape).bool()

            # for _audio_start, _audio_end in zip(audio_token_starts[0], audio_token_ends[0]):
            #     audio_label_mask[:, _audio_start: _audio_end] = True
            #     audio_token_mask[:, _audio_start-1: _audio_end-1] = True
            # text_token_mask = ~audio_token_mask
            # text_label_mask = ~audio_label_mask
            # logits_text = logits[..., :text_vocab_size].contiguous()
            # labels_text = labels.contiguous()
            # ce_loss_text = ForCausalLMLoss(logits=logits_text, labels=labels_text, vocab_size=text_vocab_size, shift=True, **kwargs)

            # num_text_labels = labels[text_label_mask].ne(-100).sum()
            # num_audio_labels = audio_token_mask.sum()
            # num_labels = labels.ne(-100).sum()
            # assert num_text_labels + num_audio_labels == num_labels, \
            #     f"{num_text_labels=} + {num_audio_labels=} == {num_labels=}"
            # num_codebook = self.config.num_codebook
            # codebook_size = self.config.codebook_size
            # ce_loss_audio, ce_loss_audios = 0, []
            # if audio_label_mask.any():
            #     for i in range(1, num_codebook): # text_vocab_size start from <audio_1_0>
            #         logits_s = text_vocab_size + (i-1)*codebook_size
            #         logits_e = text_vocab_size + i*codebook_size
            #         logits_audio_i = logits[audio_token_mask][..., logits_s:logits_e].contiguous()
            #         labels_audio_i = audio_labels.squeeze(0)[i].contiguous()
            #         ce_loss_audio_i = ForCausalLMLoss(
            #             logits=logits_audio_i, labels=labels_audio_i, vocab_size=codebook_size, shift=False, **kwargs)
            #         ce_loss_audios.append(ce_loss_audio_i)
            #     ce_loss_audio = torch.stack(ce_loss_audios).mean()
            #     assert not torch.isnan(ce_loss_audio).any(), f"{ce_loss_audio=} {ce_loss_audio.size()=}"
            # losses = [ce_loss_text] + ce_loss_audios
            # _losses = torch.stack(losses).tolist()

            # loss = ce_loss_text + ce_loss_audio
            ce_loss_text, ce_loss_audio, loss = self.compute_xy_loss(
                logits, labels, audio_labels,
                audio_token_starts,
                audio_token_ends,
                mtp_idx=-1,
                **kwargs
            )

            # if is_main_process():
            #     logger.info(f"\tavg: {loss} | text: {ce_loss_text} | audio: {ce_loss_audio} | all losses: {_losses}")
            # assert not torch.isnan(loss).any(), f"{loss=} {loss.size()=}"

        # ===============================================================================================
        if labels is not None and self.config.num_nextn_predict_layers > 0:

            if self.lm_head.weight.requires_grad:
                # if inputs_embeds is None:
                #     inputs_embeds = self.model.embed_tokens(input_ids)

                # inputs_embeds = self.process_inputs(
                #     inputs_embeds, audio_tokens, audio_token_starts, audio_token_ends
                # )
                inputs_embeds = outputs.inputs_embeds

                inputs_embeds = inputs_embeds
                hidden_states = hidden_states
                kl_labels = logits

            else:
                with torch.no_grad():
                    # if inputs_embeds is None:
                    #     inputs_embeds = self.model.embed_tokens(input_ids)
                    # inputs_embeds = self.process_inputs(
                    #     inputs_embeds, audio_tokens, audio_token_starts, audio_token_ends
                    # )
                    inputs_embeds = outputs.inputs_embeds

                    inputs_embeds = inputs_embeds.detach()
                    hidden_states = hidden_states.detach()
                    kl_labels = logits.detach()

            if self.lm_head.weight.requires_grad:
                pass
            else:
                loss = 0.0

            def mask_to_position(mask):
                if mask.ndim == 2:
                    assert len(mask) == 1
                pos = torch.where(mask.flatten())[0]
                if pos.numel() == 0:
                    dummy_starts, dummy_ends = pos.clone(), pos.clone()
                    return dummy_starts.unsqueeze(0), dummy_ends.unsqueeze(0)
                diffs = torch.diff(pos)
                breaks = torch.where(diffs != 1)[0]
                starts = torch.cat((torch.tensor([0]).to(pos), breaks + 1))
                ends = torch.cat((breaks, torch.tensor([len(pos) - 1]).to(pos)))
                return pos[starts].unsqueeze(0), pos[ends].unsqueeze(0) + 1

            audio_token_mask = torch.zeros(input_ids.shape).bool().to(inputs_embeds.device)
            audio_label_mask = torch.zeros(input_ids.shape).bool().to(inputs_embeds.device)
            for _audio_start, _audio_end in zip(audio_token_starts[0], audio_token_ends[0]):
                audio_label_mask[:, _audio_start: _audio_end] = True
                audio_token_mask[:, _audio_start-1: _audio_end-1] = True

            for mtp_idx in range(self.config.num_nextn_predict_layers):
                # import pdb; pdb.set_trace()
                # SFT with data packing
                if True:
                    mtp_mask = position_ids > mtp_idx
                    # input_ids = input_ids[mtp_mask].unsqueeze(0)
                    inputs_embeds = inputs_embeds[mtp_mask].unsqueeze(0)
                    if attention_mask is not None:
                        attention_mask = attention_mask[mtp_mask].unsqueeze(0)
                    if position_ids is not None:
                        position_ids = position_ids[mtp_mask].unsqueeze(0)
                    labels = labels[mtp_mask].unsqueeze(0)
                    kl_labels = kl_labels[mtp_mask].unsqueeze(0)

                    audio_label_mask = audio_label_mask[mtp_mask].unsqueeze(0)


                    audio_token_mask = audio_token_mask[mtp_mask].unsqueeze(0)
                    audio_token_starts, audio_token_ends = mask_to_position(audio_label_mask)
                    for s, e in zip(audio_token_starts[0], audio_token_ends[0]):
                        assert audio_label_mask[:,s:e].all(), f'{mtp_idx}'
                    non_audio_token_starts, non_audio_token_ends = mask_to_position(~audio_label_mask)
                    for s, e in zip(non_audio_token_starts[0], non_audio_token_ends[0]):
                        assert (~audio_label_mask[:,s:e]).all(), f'{mtp_idx}'
                    assert (audio_token_ends-audio_token_starts).sum() == audio_label_mask.sum(), f'{mtp_idx}'

                    mtp_mask = torch.cat((mtp_mask[:, 1:], mtp_mask[:, :1]), dim=1)
                    hidden_states = hidden_states[mtp_mask].unsqueeze(0)

                    cu_seq_lens_q, cu_seq_lens_k, max_length_q, max_length_k = prepare_fa2_from_position_ids_for_mtp(position_ids, mtp_idx)
                    # kwargs["cu_seq_lens_q"] = cu_seq_lens_q
                    # kwargs["cu_seq_lens_k"] = cu_seq_lens_k
                    # kwargs["max_length_q"] = max_length_q
                    # kwargs["max_length_k"] = max_length_k

                    # print(f"{cu_seq_lens_q}")
                    # print(f"{cu_seq_lens_k}")
                    # print(f"{max_length_q}")
                    # print(f"{max_length_k}")
                # import pdb; pdb.set_trace()
                mtp_outputs, _, mtp_loss = self.mtp_forward(
                    mtp_idx,
                    input_ids=None,
                    hidden_states=hidden_states,
                    attention_mask=attention_mask,
                    position_ids=position_ids,
                    past_key_values=past_key_values,
                    inputs_embeds=inputs_embeds,
                    labels=labels,
                    kl_labels=kl_labels,
                    use_cache=use_cache,
                    output_attentions=output_attentions,
                    output_hidden_states=output_hidden_states,
                    return_dict=return_dict,
                    cache_position=cache_position,
                    num_logits_to_keep=num_logits_to_keep,
                    cu_seq_lens_q=cu_seq_lens_q,
                    cu_seq_lens_k=cu_seq_lens_k,
                    max_length_q=max_length_q,
                    max_length_k=max_length_k,
                    audio_labels=audio_labels,
                    audio_token_starts=audio_token_starts, # left shift mtp_idx+1
                    audio_token_ends=audio_token_ends, # left shift mtp_idx+1
                    **kwargs,
                )

                loss += sum(mtp_loss) / self.config.num_nextn_predict_layers * self.config.mtp_loss_weight

                hidden_states = mtp_outputs.last_hidden_state

        if not self.training:
            self.mtp_idx = 0

            if use_cache:
                if self.hidden_states[self.mtp_idx] is None:
                    self.hidden_states[self.mtp_idx] = hidden_states

                else:
                    self.hidden_states[self.mtp_idx] = torch.cat([self.hidden_states[self.mtp_idx], hidden_states], dim=1)

            else:
                self.hidden_states[self.mtp_idx] = hidden_states

        # ===============================================================================================
        return CausalLMOutputWithPast(
            loss=loss,
            logits=logits,
            past_key_values=outputs.past_key_values,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
        )

    def _prepare_mtp_for_generation(
        self,
        mtp_inference_mode,
        max_new_tokens,
    ):

        self.input_ids = None
        self.inputs_embeds = None
        self.hidden_states = [None] * (self.config.num_nextn_predict_layers + 1)
        self.position_ids = None
        self.attention_mask = None

        self.mtp_idx = -1
        self.num_prefill_tokens = -1

        assert isinstance(mtp_inference_mode, list)
        assert len(mtp_inference_mode) >= 2
        assert len(mtp_inference_mode) % 2 == 0

        main_nums = mtp_inference_mode[::2]
        mtp_nums = mtp_inference_mode[1::2]

        mtp_inference_mode = []
        while len(mtp_inference_mode) < max_new_tokens:

            if len(mtp_nums) > 1:
                mtp_num = mtp_nums.pop(0)
            else:
                mtp_num = mtp_nums[0]

            if len(main_nums) > 1:
                main_num = main_nums.pop(0)
            else:
                main_num = main_nums[0]

            mtp_inference_mode += "M" * main_num + "m" * mtp_num

        self.mtp_inference_mode = mtp_inference_mode

    def _prepare_cache_for_generation(self, *args, **kwargs):

        generation_config = args[0]
        mtp_inference_mode = getattr(generation_config, "mtp_inference_mode", [1, self.config.num_nextn_predict_layers])
        max_new_tokens = generation_config.max_new_tokens

        self._prepare_mtp_for_generation(mtp_inference_mode, max_new_tokens)

        return super()._prepare_cache_for_generation(*args, **kwargs)


@add_start_docstrings(
    """
    The Qwen3 Model transformer with a sequence classification head on top (linear layer).

    [`Qwen3ForSequenceClassification`] uses the last token in order to do the classification, as other causal models
    (e.g. GPT-2) do.

    Since it does classification on the last token, it requires to know the position of the last token. If a
    `pad_token_id` is defined in the configuration, it finds the last token that is not a padding token in each row. If
    no `pad_token_id` is defined, it simply takes the last value in each row of the batch. Since it cannot guess the
    padding tokens when `inputs_embeds` are passed instead of `input_ids`, it does the same (take the last value in
    each row of the batch).
    """,
    QWEN3_START_DOCSTRING,
)
class Qwen3ForSequenceClassification(Qwen3PreTrainedModel):
    def __init__(self, config):
        super().__init__(config)
        self.num_labels = config.num_labels
        self.model = Qwen3Model(config)
        self.score = nn.Linear(config.hidden_size, self.num_labels, bias=False)

        # Initialize weights and apply final processing
        self.post_init()

    def get_input_embeddings(self):
        return self.model.embed_tokens

    def set_input_embeddings(self, value):
        self.model.embed_tokens = value

    @can_return_tuple
    @add_start_docstrings_to_model_forward(QWEN3_INPUTS_DOCSTRING)
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        attention_mask: Optional[torch.Tensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        labels: Optional[torch.LongTensor] = None,
        use_cache: Optional[bool] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
    ) -> SequenceClassifierOutputWithPast:
        r"""
        labels (`torch.LongTensor` of shape `(batch_size,)`, *optional*):
            Labels for computing the sequence classification/regression loss. Indices should be in `[0, ...,
            config.num_labels - 1]`. If `config.num_labels == 1` a regression loss is computed (Mean-Square loss), If
            `config.num_labels > 1` a classification loss is computed (Cross-Entropy).
        """

        transformer_outputs: BaseModelOutputWithPast = self.model(
            input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
        )
        hidden_states = transformer_outputs.last_hidden_state
        logits = self.score(hidden_states)

        if input_ids is not None:
            batch_size = input_ids.shape[0]
        else:
            batch_size = inputs_embeds.shape[0]

        if self.config.pad_token_id is None and batch_size != 1:
            raise ValueError("Cannot handle batch sizes > 1 if no padding token is defined.")
        if self.config.pad_token_id is None:
            last_non_pad_token = -1
        elif input_ids is not None:
            # To handle both left- and right- padding, we take the rightmost token that is not equal to pad_token_id
            non_pad_mask = (input_ids != self.config.pad_token_id).to(logits.device, torch.int32)
            token_indices = torch.arange(input_ids.shape[-1], device=logits.device, dtype=torch.int32)
            last_non_pad_token = (token_indices * non_pad_mask).argmax(-1)
        else:
            last_non_pad_token = -1
            logger.warning_once(
                f"{self.__class__.__name__} will not detect padding tokens in `inputs_embeds`. Results may be "
                "unexpected if using padding tokens in conjunction with `inputs_embeds.`"
            )

        pooled_logits = logits[torch.arange(batch_size, device=logits.device), last_non_pad_token]

        loss = None
        if labels is not None:
            loss = self.loss_function(logits=logits, labels=labels, pooled_logits=pooled_logits, config=self.config)

        return SequenceClassifierOutputWithPast(
            loss=loss,
            logits=pooled_logits,
            past_key_values=transformer_outputs.past_key_values,
            hidden_states=transformer_outputs.hidden_states,
            attentions=transformer_outputs.attentions,
        )


@add_start_docstrings(
    """
    The Qwen3 Model transformer with a token classification head on top (a linear layer on top of the hidden-states
    output) e.g. for Named-Entity-Recognition (NER) tasks.
    """,
    QWEN3_START_DOCSTRING,
)
class Qwen3ForTokenClassification(Qwen3PreTrainedModel):
    def __init__(self, config):
        super().__init__(config)
        self.num_labels = config.num_labels
        self.model = Qwen3Model(config)
        if getattr(config, "classifier_dropout", None) is not None:
            classifier_dropout = config.classifier_dropout
        elif getattr(config, "hidden_dropout", None) is not None:
            classifier_dropout = config.hidden_dropout
        else:
            classifier_dropout = 0.1
        self.dropout = nn.Dropout(classifier_dropout)
        self.score = nn.Linear(config.hidden_size, config.num_labels)

        # Initialize weights and apply final processing
        self.post_init()

    def get_input_embeddings(self):
        return self.model.embed_tokens

    def set_input_embeddings(self, value):
        self.model.embed_tokens = value

    @can_return_tuple
    @add_start_docstrings_to_model_forward(QWEN3_INPUTS_DOCSTRING)
    @add_code_sample_docstrings(
        checkpoint=_CHECKPOINT_FOR_DOC,
        output_type=TokenClassifierOutput,
        config_class=_CONFIG_FOR_DOC,
    )
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        attention_mask: Optional[torch.Tensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        labels: Optional[torch.LongTensor] = None,
        use_cache: Optional[bool] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
    ) -> TokenClassifierOutput:
        r"""
        labels (`torch.LongTensor` of shape `(batch_size,)`, *optional*):
            Labels for computing the sequence classification/regression loss. Indices should be in `[0, ...,
            config.num_labels - 1]`. If `config.num_labels == 1` a regression loss is computed (Mean-Square loss), If
            `config.num_labels > 1` a classification loss is computed (Cross-Entropy).
        """

        outputs: BaseModelOutputWithPast = self.model(
            input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
        )
        sequence_output = outputs.last_hidden_state
        sequence_output = self.dropout(sequence_output)
        logits = self.score(sequence_output)

        loss = None
        if labels is not None:
            loss = self.loss_function(logits, labels, self.config)

        return TokenClassifierOutput(
            loss=loss,
            logits=logits,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
        )


@add_start_docstrings(
    """
The Qwen3 Model transformer with a span classification head on top for extractive question-answering tasks like
SQuAD (a linear layer on top of the hidden-states output to compute `span start logits` and `span end logits`).
    """,
    QWEN3_START_DOCSTRING,
)
class Qwen3ForQuestionAnswering(Qwen3PreTrainedModel):
    base_model_prefix = "transformer"

    def __init__(self, config):
        super().__init__(config)
        self.transformer = Qwen3Model(config)
        self.qa_outputs = nn.Linear(config.hidden_size, 2)

        # Initialize weights and apply final processing
        self.post_init()

    def get_input_embeddings(self):
        return self.transformer.embed_tokens

    def set_input_embeddings(self, value):
        self.transformer.embed_tokens = value

    @can_return_tuple
    @add_start_docstrings_to_model_forward(QWEN3_INPUTS_DOCSTRING)
    def forward(
        self,
        input_ids: Optional[torch.LongTensor] = None,
        attention_mask: Optional[torch.FloatTensor] = None,
        position_ids: Optional[torch.LongTensor] = None,
        past_key_values: Optional[Cache] = None,
        inputs_embeds: Optional[torch.FloatTensor] = None,
        start_positions: Optional[torch.LongTensor] = None,
        end_positions: Optional[torch.LongTensor] = None,
        output_attentions: Optional[bool] = None,
        output_hidden_states: Optional[bool] = None,
        **kwargs,
    ) -> QuestionAnsweringModelOutput:
        r"""
        start_positions (`torch.LongTensor` of shape `(batch_size,)`, *optional*):
            Labels for position (index) of the start of the labelled span for computing the token classification loss.
            Positions are clamped to the length of the sequence (`sequence_length`). Position outside of the sequence
            are not taken into account for computing the loss.
        end_positions (`torch.LongTensor` of shape `(batch_size,)`, *optional*):
            Labels for position (index) of the end of the labelled span for computing the token classification loss.
            Positions are clamped to the length of the sequence (`sequence_length`). Position outside of the sequence
            are not taken into account for computing the loss.
        """

        outputs: BaseModelOutputWithPast = self.transformer(
            input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            output_attentions=output_attentions,
            output_hidden_states=output_hidden_states,
        )

        sequence_output = outputs.last_hidden_state

        logits = self.qa_outputs(sequence_output)
        start_logits, end_logits = logits.split(1, dim=-1)
        start_logits = start_logits.squeeze(-1).contiguous()
        end_logits = end_logits.squeeze(-1).contiguous()

        loss = None
        if start_positions is not None and end_positions is not None:
            loss = self.loss_function(start_logits, end_logits, start_positions, end_positions, **kwargs)

        return QuestionAnsweringModelOutput(
            loss=loss,
            start_logits=start_logits,
            end_logits=end_logits,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
        )


def prepare_fa2_from_position_ids_for_mtp(position_ids, mtp_idx):
    position_ids = position_ids.flatten()
    indices_q = torch.arange(position_ids.size(0), device=position_ids.device, dtype=torch.int32)

    cu_seq_lens = torch.cat(
        (
            indices_q[position_ids == mtp_idx + 1],
            torch.tensor(position_ids.size(), device=position_ids.device, dtype=torch.int32),
        )
    )

    max_length = position_ids.max() + 1 - 1 - mtp_idx

    return cu_seq_lens, cu_seq_lens, max_length, max_length


def is_main_process(local=True):
    import os
    if torch.distributed.is_initialized() and torch.distributed.get_world_size() > 1:
        if local:
            rank = int(os.environ["LOCAL_RANK"])
        else:
            rank = torch.distributed.get_rank()
        _is_main_process = rank == 0
        return _is_main_process
    return True


